        "id": "0e058d0d-4178-4e4f-9452-695835c30fef",
        "nombre": "Detectar pensamientos",
        "nivel": 2,
        "escuela": "Adivinación",
        "alcancePies": null,
        "componentes": {
          "verbal": true,
          "material": "1 pieza de cobre.",
          "somatico": true,
          "consumeMaterial": false
        },
        "duracion": "Hasta 1 minuto",
